def find_Max_Num(digits):
    digits.sort(reverse=True)
    return int(''.join(map(str, digits)))

assert find_Max_Num([1,2,3]) == 321
assert find_Max_Num([4,5,6,1]) == 6541
assert find_Max_Num([1,2,3,9]) == 9321

